+export function normalizeRetiredRepairEnvNames(value: string) {
+  let normalized = value;
+  for (const [retiredName, currentName] of RETIRED_REPAIR_ENV_NAMES) {
+    normalized = normalized.replaceAll(retiredName, currentName);
+  }
+  return normalized;
+}
